#!/usr/bin/env node
// tools/build_synth_browser_bundle.js
// Wraps dist/compiler.synth.js into demo/compiler.synth.js (browser IIFE)
// API matches demo/synth.compiler.js: SynthCompiler.compile / check / stdlib / version

const fs   = require('fs')
const path = require('path')

const ROOT    = path.join(__dirname, '..')
const DIST    = path.join(ROOT, 'dist', 'compiler.synth.js')
const STDLIB  = path.join(ROOT, 'demo', 'synth.stdlib.js')
const OUT     = path.join(ROOT, 'demo', 'compiler.synth.js')

function isFresh(output, inputs) {
  if (!fs.existsSync(output)) return false
  const outMtime = fs.statSync(output).mtimeMs
  return inputs.every(f => fs.existsSync(f) && fs.statSync(f).mtimeMs <= outMtime)
}

const INPUTS = [DIST, STDLIB, __filename]
if (isFresh(OUT, INPUTS) && process.argv[2] !== '--force') {
  console.log('✓ compiler.synth.js  up to date (use --force to rebuild)')
  process.exit(0)
}

if (!fs.existsSync(DIST)) {
  console.error('missing dist/compiler.synth.js — run npm run build:compiler first')
  process.exit(1)
}

const compilerBody = fs.readFileSync(DIST, 'utf8')
const stdlibRaw    = fs.readFileSync(STDLIB, 'utf8')
const stdlibContent = '\n' + stdlibRaw.replace(/^(\/\/[^\n]*\n)+/, '')

const bundle = `// Synth self-hosted compiler — browser bundle
// Generated by tools/build_synth_browser_bundle.js — do not edit
// Source: compiler/driver.syn (TS bootstrap → dist/compiler.synth.js)
// API: SynthCompiler.compile(src) → { js, errors, warnings }
//      SynthCompiler.check(src)   → { warnings, errors }
//      SynthCompiler.stdlib       → stdlib JS string
//      SynthCompiler.version      → "1.0.0-selfhost"
//      SynthCompiler.backend      → "synth"
(function (global) {
  "use strict";

  const SYNTH_STDLIB = ${JSON.stringify(stdlibContent)};

  const __synth_compiler = (function () {
${compilerBody}
    return { compile, check_source, tokenize, parse, generate, check };
  })();

  function formatWarnings(diags) {
    return (diags || []).map(d => ({
      severity: d.severity || 'warning',
      message:  d.message,
      line:     d.line ?? 1,
      col:      d.col ?? 1,
    }))
  }

  function compile(source) {
    try {
      const result = __synth_compiler.compile(source)
      return {
        js: result.js,
        errors: [],
        warnings: formatWarnings(result.warnings),
      }
    } catch (e) {
      return {
        js: null,
        errors: [{ message: String(e), line: 1, col: 1, kind: 'error' }],
        warnings: [],
      }
    }
  }

  function check(source) {
    try {
      const warnings = __synth_compiler.check_source(source)
      return { warnings: formatWarnings(warnings), errors: [] }
    } catch (e) {
      return {
        warnings: [],
        errors: [{ message: String(e), line: 1, col: 1 }],
      }
    }
  }

  global.SynthCompiler = {
    compile,
    check,
    version: '1.0.0-selfhost',
    backend: 'synth',
    stdlib: SYNTH_STDLIB,
  }

})(typeof window !== 'undefined' ? window : typeof globalThis !== 'undefined' ? globalThis : this);
`

fs.writeFileSync(OUT, bundle, 'utf8')
const lines = bundle.split('\n').length
console.log(`✓ compiler.synth.js  ${lines} lines  →  demo/compiler.synth.js`)
